INSERT INTO cases (slug, title, description, keywords, damage_type, litigation_method, required_docs, process, phone, status, tagline, created_at) VALUES
('luna-crypto-fraud', '루나(LUNA) 암호화폐 투자사기 단체소송', '테라·루나 붕괴로 인한 투자 손실 피해자를 위한 단체소송입니다. 과대광고 및 허위정보 유포에 따른 손해배상을 청구합니다.', '루나,테라,LUNA,암호화폐,가상자산', '가상자산 투자 손실, 과대광고 피해', '손해배상 청구 소송, 단체소송', '거래내역서, 입출금 내역, 신분증 사본', '1) 상담 접수 2) 서류 검토 3) 참여 의사 확인 4) 소송 제기 5) 판결 및 집행', '1588-1234', '접수진행중', '루나 피해 1차 단체소송 진행중', '2024-01-15'),
('ftx-exchange-collapse', 'FTX 거래소 자금 인출불가 피해 소송', 'FTX 거래소 파산으로 인한 자금 인출불가 피해자를 위한 집단 손해배상 소송을 진행합니다.', 'FTX,암호화폐거래소,가상자산', '거래소 파산, 자금 인출 불가', '집단손해배상청구, 해외 파산절차 참여', 'FTX 계정 스크린샷, 거래내역, 입출금 내역', '1) 피해규모 신고 2) 파산관재인 등록 3) 국내 소송 병행 4) 배당참여', '1588-1235', '접수진행중', 'FTX 피해자 단체 대응', '2024-02-01'),
('jeonse-fraud-seoul', '서울 전세사기 피해자 단체소송', '전세보증금 반환받지 못한 피해자를 위한 환부신청 및 손해배상 단체소송을 진행합니다.', '전세사기,전세보증금,부동산', '전세보증금 미반환, 집주인 파산', '환부신청, 손해배상 청구 소송', '전세계약서, 등본, 보증금 입금증', '1) 상담 및 서류 접수 2) 환부신청 3) 소송 병행 4) 배당금 수령', '1588-1236', '접수진행중', '전세사기 피해 보증금 환수', '2024-02-15'),
('lime-kiwoom-investment-fraud', '라임·키움 자산운용 펀드투자사기', '라임·키움 자산운용 펀드 투자 손실 피해자를 위한 집단소송입니다. 허위·과대 수익 광고 책임을 추궁합니다.', '라임,키움,펀드,투자사기', '펀드 투자 손실, 허위 광고', '집단소송, 손해배상 청구', '펀드 가입증빙, 거래확인서, 증권사 입출금 내역', '1) 피해 접수 2) 원인분석 3) 소송 제기 4) 집단 참여', '1588-1237', '접수진행중', '라임·키움 펀드 피해 단체소송', '2024-03-01'),
('oasis-marketplace-fraud', '오아시스 마켓 플랫폼 투자사기', '오아시스 마켓 P2P 투자 금융사기 피해자를 위한 단체소송을 진행합니다. 이자 수령 불가 및 원금 회수 지원.', '오아시스,마켓플랫폼,P2P,투자', 'P2P 투자금 미회수, 이자 연체', '단체 손해배상 청구, 환부신청', '투자계약서, 입출금 내역, 플랫폼 거래 내역', '1) 피해 신고 2) 플랫폼 파악 3) 단체소송 4) 배당', '1588-1238', '접수진행중', '오아시스 마켓 피해 단체 대응', '2024-03-10'),
('tokens-com-polygon-fraud', '토큰스컴퍼니 폴리곤 코인 사기', '토큰스컴퍼니 관련 폴리곤 코인 투자사기 피해자를 위한 단체소송입니다. 프로젝트 퍼디 사건 연관.', '토큰스,폴리곤,POL,가상자산', '가상자산 투자 사기, 허위 정보', '손해배상 청구, 형사고발 병행', '거래내역, 지갑 주소, 입금증', '1) 상담 2) 증거 수집 3) 소송 제기 4) 형사 참고인 신청', '1588-1239', '접수진행중', '토큰스컴퍼니 피해 집단소송', '2024-03-20'),
('wemix-delisting-loss', '위믹스(WEMIX) 상장폐지 손실 단체소송', '위믹스 상장폐지로 인한 급락 손실 피해자를 위한 단체소송입니다. 거래소·발행사 책임 추궁.', '위믹스,WEMIX,상장폐지,암호화폐', '상장폐지 급락 손실', '단체소송, 손해배상 청구', '거래소 거래내역, 보유수량 증빙', '1) 피해 규모 파악 2) 원인 분석 3) 단체소송 4) 판결 대기', '1588-1240', '접수진행중', '위믹스 상장폐지 피해 집단 대응', '2024-04-01'),
('digital-bank-deposit-fraud', '인터넷전문은행 예금사기 단체소송', '인터넷전문은행 관련 피싱·예금사기 피해자의 손해배상 청구를 지원합니다. 금융기관 책임 추궁.', '인터넷은행,카카오뱅크,토스뱅크,예금', '피싱, 예금 인출 사기', '손해배상 청구, 금융감독원 진정', '통장 사본, 거래내역, 사기사실 신고확인서', '1) 상담 2) 금감원 진정 3) 소송 검토 4) 손해배상 청구', '1588-1241', '접수진행중', '인터넷은행 예금사기 피해 보상', '2024-04-15')
